const rows = $input.all();
if (rows.length === 0 || !rows[0].json.subreddit_name) {
  return [{ json: { text: 'No monitored subreddits or posts found.', post_ids: [], ref_map: {} } }];
}

const subreddits = {};
const postIds = new Set();

rows.forEach(row => {
  const data = row.json;
  const subName = data.subreddit_name;
  if (!subreddits[subName]) {
    subreddits[subName] = { active: data.subreddit_active, posts: {} };
  }
  if (data.post_id) {
    postIds.add(data.post_id);
    if (!subreddits[subName].posts[data.post_id]) {
      subreddits[subName].posts[data.post_id] = {
        title: data.post_title,
        content: data.post_content,
        author: data.post_author,
        url: data.post_url,
        created_at: data.post_created_at,
        comments: []
      };
    }
    if (data.comment_id) {
      subreddits[subName].posts[data.post_id].comments.push({
        author: data.comment_author,
        content: data.comment_content,
        created_at: data.comment_created_at
      });
    }
  }
});

// Assign a sequential [ref:N] number to every post
// ref_map: { '1': { title, url }, '2': { title, url }, ... }
const refMap = {};
let refCounter = 1;

let text = 'Here is the Reddit monitoring data:\n\n';
text += '=== Monitored Subreddits ===\n';
for (const [subName, subInfo] of Object.entries(subreddits)) {
  text += `- r/${subName} (Status: ${subInfo.active ? 'Active' : 'Inactive'})\n`;
}
text += '\n=== New Posts & Comments (last 24h) ===\n';
text += '(Each post has a citation number like [ref:1]. Use that number inline in your summary.)\n\n';

for (const [subName, subInfo] of Object.entries(subreddits)) {
  const postsList = Object.values(subInfo.posts);
  if (postsList.length === 0) continue;

  text += `Subreddit: r/${subName}\n`;
  postsList.forEach(post => {
    const refId = refCounter++;
    refMap[String(refId)] = { title: post.title || 'Post', url: post.url || '' };

    text += `  [ref:${refId}] ${post.title || 'No Title'} (by u/${post.author || 'unknown'})\n`;
    text += `  Content: ${(post.content || '').substring(0, 500)}\n`;
    if (post.comments.length > 0) {
      text += `  Comments:\n`;
      post.comments.slice(0, 5).forEach(comment => {
        text += `    - [u/${comment.author || 'unknown'}]: ${(comment.content || '').substring(0, 300)}\n`;
      });
    }
    text += `  -------------------------------------------\n`;
  });
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/bella.md', 'utf8');
} catch (e) {
  persona = 'Warm, charming Italian secretary named Bella.';
}

return [{ json: { text, post_ids: Array.from(postIds), ref_map: refMap, bella_persona: persona } }];

// Get the raw LLM response
const response = $input.first().json.response || '';

// Get the ref_map built deterministically in Format Posts for LLM
const refMap = $('Format Posts for LLM').first().json.ref_map || {};

// Step 1: Replace [ref:N] citation tags with Slack hyperlinks <url|title>
let text = response.replace(/\[ref:(\d+)\]/g, (match, n) => {
  const ref = refMap[n];
  if (!ref || !ref.url) return '';
  return `<${ref.url}|${ref.title}>`;
});

// Step 2: Convert remaining markdown to Slack format
text = text.replace(/\*\*(.*?)\*\*/g, '*$1*');
text = text.replace(/#{1,6}\s+(.*?)($|\n)/g, '*$1*\n');
// Convert any stray markdown links the model may have snuck in
text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>');

return [{ json: { response: text } }];
